<script>
import { useRouter, useRoute } from 'vue-router';
export default {
	name: 'App',
	setup: () => {
		const router = useRouter();
		const route = useRoute();
		const routes = router
			.getRoutes()
			.map((x) => ({
				path: x.path,
				name: x.name,
				title: x.meta.title,
			}))
			.filter((x) => x.path !== '/');
		return {
			routes,
			route,
		};
	},
};
</script>

<template>
	<div id="content">
		<router-view />
	</div>
	<div id="credit">
		<template v-for="r of routes" :key="r.name">
			<template v-if="route.path !== r.path">
				<router-link :to="{ name: r.name }">{{ r.title }}</router-link>
			</template>
			<template v-else>
				<span>{{ r.title }}</span>
			</template>
			|
		</template>
		by <router-link :to="{ name: 'home' }">Deztar</router-link>
	</div>
</template>

<style lang="scss">
@import '@/styles/base.scss';
#app {
	min-height: calc(100vh - 1ch);
	display: grid;
	grid-template-areas: 'content' 'credit';
	grid-template-rows: auto max-content;
	justify-items: center;
}
#content {
	grid-area: content;
}
#credit {
	grid-area: credit;
	align-self: end;
	margin: 1ch 0;
}
</style>
