import { createRouter, createWebHistory, RouteRecordRaw } from 'vue-router'
import HomePage from '@/pages/HomePage.vue'

const routes: Array<RouteRecordRaw> = [
	{
		path: '/',
		name: 'home',
		component: HomePage,
	},
	{
		path: '/rimworld-crop-planner',
		name: 'rimworldPlanner',
		component: () => import('@/pages/RimworldPlanner.vue'),
		meta: {
			title: 'Rimworld Crop Planner',
		}
	},
	{
		path: '/battle-brothers-planner',
		name: 'brothersPlanner',
		component: () => import('@/pages/BrothersPlanner.vue'),
		meta: {
			title: 'Battle Brothers Planner',
		}
	},
]

const router = createRouter({
	history: createWebHistory(process.env.BASE_URL),
	routes,
})

export default router;
