import { Module } from 'vuex';
import { assignDeepProp, buildDictFromArray, checkAllAnd, cloneJSON } from '@/helpers';
import {
	RecordBase,
	RecordExtended,
	Pawn,
	Recipe,
	Crop,
	ProduceType,
	Soil,
	EdgeCase,
	Mode,
} from '@/types/rimworldTypes';
import {
	crops,
	filterDefault,
	pawns,
	recipes,
	soil,
	realGrowthMult,
	drugs,
	nutritionMult,
	barrelMult,
	recordDefault,
} from '@/data/rimworldData';

interface Settings {
	growingSeason: number;
	offSeason: number;
	yieldMultiplier: number;
	drugSoil: {
		[key: string]: string;
	}
}

interface Dict<Type> { [key: string]: Type }

const generatorAccepted = ['Raw', 'Kibble', 'Pemmican'];

const settingsDefault: Settings = {
	growingSeason: 60,
	offSeason: 20,
	yieldMultiplier: 1,
	drugSoil: {
		Beer: 'Regular',
		Tea: 'Regular',
		Joint: 'Regular',
	}
}

const moduleRw: Module<{
	data: RecordBase[];
	filter: (boolean | null)[];
	settings: Settings;
}, any> = {
	namespaced: true,
	state: {
		data: [],
		filter: [],
		settings: cloneJSON(settingsDefault),
	},
	getters: {
		pawnFilter(state) {
			return pawns.map((x, i) => ({ name: x.name, disabled: state.filter[i] || false }));
		},
		pawns: (): Dict<Pawn> => {
			return buildDictFromArray<Pawn>(pawns, 'name');
		},
		recipes: (): Dict<Recipe> => {
			return buildDictFromArray<Recipe>(recipes, 'name');
		},
		crops: (): Dict<Crop> => {
			return buildDictFromArray<Crop>(
				crops.filter(x => x.produce === ProduceType.Nutrition || !x.produce),
				'name'
			);
		},
		soil: (): Dict<Soil> => {
			return buildDictFromArray<Soil>(soil, 'name');
		},
		dataExtended: (state, getters) => state.data.map(item => {
			const ext: RecordExtended = {
				...item,
				pawn: getters['pawns'][item.pawn],
				recipe: getters['recipes'][item.recipe],
				crop: getters['crops'][item.crop],
				options: {},
			}
			ext.useMeat = (item.useMeat && ext.recipe.input.nut) ? true : false;
			let opts: { [key: string]: boolean } = {};
			// Recipes
			if (item.pawn === EdgeCase.Generator) {
				for (const r of recipes) {
					opts[r.name] = generatorAccepted.includes(r.name);
				}
			} else if (!ext.pawn.grazer) {
				for (const r of recipes) {
					opts[r.name] = r.name !== EdgeCase.Grazing;
				}
			} else {
				for (const r of recipes) {
					opts[r.name] = true;
				}
			}
			ext.options['recipe'] = opts;
			// Crops
			opts = {};
			const checks: Array<(value: any) => boolean> = [];
			if (item.recipe !== EdgeCase.Grazing) {
				checks.push((x: Crop) => x.produce === ProduceType.Nutrition)
				if (item.recipe !== EdgeCase.Kibble) {
					if (!(item.recipe === EdgeCase.Raw && ext.pawn.grazer)) {
						checks.push((x: Crop) => x.name !== EdgeCase.Haygrass);
					}
				}
			}
			for (const [k, v] of Object.entries(getters['crops'])) {
				opts[k] = checkAllAnd(v, checks);
			}
			ext.options['crop'] = opts;
			// Soil
			opts = {};
			if (item.crop === EdgeCase.Nutrifungus) {
				for (const s of soil) {
					opts[s.name] = s.name === EdgeCase.Stony;
				}
			} else {
				for (const s of soil) {
					opts[s.name] = (s.name !== EdgeCase.Hydroponics) || ext.crop.hydroponics || false;
				}
			}
			ext.options['soil'] = opts;
			//Modes
			opts = {};
			for (const m in Mode) {
				opts[m] = true;
			}
			if (item.recipe === EdgeCase.Grazing) {
				opts[Mode.Stockpile] = false;
				opts[Mode.Greenhouse] = false;
			}
			ext.options['mode'] = opts;
			return ext;
		}),
		result: (state, getters) => {
			const farmingPlotsNeeded = (req: number, crop: Crop, soil: Soil, mode: string) => {
				const season = mode === Mode.Greenhouse ? 60 : state.settings.growingSeason;
				const growDays = crop.growDays * realGrowthMult / (1 + soil.fertility * crop.sensetivity);
				const consumeDays = mode === Mode.Stockpile ? state.settings.offSeason : 60;
				const cropYield = (crop.yield || 1) * state.settings.yieldMultiplier;
				let plots = 0;
				const harvestCount = season / growDays;
				let harvestInt = Math.floor(harvestCount);
				if (harvestInt === 0) harvestInt = 1;
				if (season === 60) {
					plots = (consumeDays / 60) * growDays * req / cropYield;
				} else {
					plots = consumeDays * req / harvestInt / cropYield;
				}
				return [Math.ceil(plots), harvestInt];
			}
			const grazingPlotsNeeded = (req: number, crop: Crop, soil: Soil, mode: string) => {
				const season = mode === Mode.Greenhouse ? 60 : state.settings.growingSeason;
				const growDays = crop.growDays * realGrowthMult / (1 + soil.fertility * crop.sensetivity);
				const plots = growDays * req / crop.nutrition;
				const harvestCount = season / growDays;
				let harvestInt = Math.floor(harvestCount);
				if (harvestInt === 0) harvestInt = 1;
				return [Math.ceil(plots), harvestInt];
			}
			const result: { [k: string]: any } = { meat: 0, production: {} };
			for (const m in Mode) {
				result[m] = {};
			}
			for (const r of state.data) {
				if (!result[r.mode][r.crop]) {
					result[r.mode][r.crop] = {};
				}
				if (!result[r.mode][r.crop][r.soil]) {
					result[r.mode][r.crop][r.soil] = { nut: 0, grazing: 0 };
				}
			}
			for (const drug of drugs) {
				result[drug.name] = 0;
			}
			for (const ext of getters['dataExtended'] as RecordExtended[]) {
				const recipe = ext.recipe;
				// Vegetables
				if (recipe.name !== EdgeCase.Grazing) {
					const vegMult = (recipe.input.veg || (ext.useMeat ? 0 : recipe.input.nut) || 0) / recipe.output.nut;
					result[ext.mode][ext.crop.name][ext.soil].nut += ext.amount * ext.pawn.consumption * vegMult;
				} else {
					result[ext.mode][ext.crop.name][ext.soil].grazing += ext.amount * ext.pawn.consumption;
				}
				// Meat
				if (recipe.input.meat || ext.useMeat) {
					let meatMult = (recipe.input.meat || recipe.input.nut || 0) / recipe.output.nut;
					if (ext.mode === Mode.Stockpile) {
						meatMult *= state.settings.offSeason / 60;
					}
					result.meat += ext.amount * meatMult * ext.pawn.consumption;
				}
				// Drugs
				if (ext.pawn.canTakeDrugs) {
					for (const drug of drugs) {
						result[drug.name] += ext.amount * (ext.drugs[drug.name] || 0);
					}
				}
				// Production
				const prod = ext.pawn.production;
				if (prod && ext.mode !== Mode.Stockpile) {
					result.production[prod.name] = ext.amount * prod.amount + (result.production[prod.name] || 0);
				}
			}

			// Calculate crops
			for (const mode in Mode) {
				for (const crop of crops) {
					if (!result[mode][crop.name]
						|| (crop.produce !== ProduceType.Nutrition && crop.name !== EdgeCase.Dandelion)) {
						continue;
					}
					for (const s of soil) {
						const r = result[mode][crop.name][s.name];
						if (!r) {
							continue;
						}
						if (r.nut) {
							r.farmingPlots = farmingPlotsNeeded(r.nut * nutritionMult, crop, s, mode);
						} else {
							r.farmingPlots = [0, 0];
						}
						if (r.grazing) {
							r.grazingPlots = grazingPlotsNeeded(r.grazing, crop, s, mode);
						} else {
							r.grazingPlots = [0, 0];
						}
					}
				}
			}
			// Calculate drugs
			result.drugs = {};
			for (const mode in Mode) {
				if (mode === Mode.Stockpile) {
					continue;
				}
				result.drugs[mode] = {};
			}
			for (const drug of drugs) {
				if (!result[drug.name]) {
					continue;
				}
				for (const mode in Mode) {
					if (mode === Mode.Stockpile) {
						continue;
					}
					const crop = crops.find(x => x.name === drug.crop);
					const s = soil.find(x => x.name === state.settings.drugSoil[drug.name]);
					if (crop && s) {
						result.drugs[mode][crop.name] = {};
						result.drugs[mode][crop.name][s.name] = {
							plots: farmingPlotsNeeded(
								result[drug.name] / drug.eff,
								crop,
								s,
								mode
							)
						};
					}
				}
			}
			if (result['Beer']) {
				result['Barrels'] = Math.ceil(result['Beer'] * barrelMult);
			}
			return result;
		},
	},
	mutations: {
		addNewItem: (state) => {
			state.data.push(cloneJSON(recordDefault));
		},
		removeItem: (state, { index }) => {
			state.data.splice(index, 1);
		},
		insertItem: (state, { index, item }) => {
			if (index >= 0) {
				state.data.splice(index, 0, item);
			} else {
				const len = state.data.length;
				state.data.splice(len + index + 1, 0, item)
			}

		},
		changeProp: (state, { index, prop, value }) => {
			assignDeepProp(state.data[index], prop, value);
		},
		changeSetting: (state, { prop, value }) => {
			assignDeepProp(state.settings, prop, value);
		},
		toggleFilter: (state, index) => {
			state.filter[index] = !state.filter[index];
		},
		emptyFilter(state) {
			state.filter = [];
		},
		defaultFilter(state) {
			state.filter = filterDefault;
		},
	},
	actions: {
		moveItem: (context, { index, newIndex }) => {
			const item = context.state.data[index];
			context.commit('removeItem', { index });
			context.commit('insertItem', { index: newIndex, item });
		},
		changeProp: (context, { index, prop, value }) => {
			const checkValue = (select: string, option: string) => {
				if (!ext.options[select][option]) {
					for (const [k, v] of Object.entries(ext.options[select])) {
						console.log(`${k} ${v}`);
						if (v) {
							context.dispatch('changeProp', { index, prop: select, value: k })
							break;
						}
					}
				}
			};
			context.commit('changeProp', { index, prop, value });
			const ext: RecordExtended = context.getters['dataExtended'][index];
			if (prop === 'pawn') {
				checkValue('recipe', ext.recipe.name);
			} else if (prop === 'recipe') {
				checkValue('crop', ext.crop.name);
				checkValue('mode', ext.mode);
			} else if (prop === 'crop') {
				checkValue('soil', ext.soil);
			} else if (prop === 'soil') {
				checkValue('mode', ext.mode);
			}
		},
		loadFromStorage: ({ state }) => {
			const obj = JSON.parse(localStorage.getItem('rimworld-data') || '{}');
			state.data = obj.data || [];
			state.filter = obj.filter || filterDefault;
			state.settings = obj.settings || settingsDefault;
		},
		saveToStorage: ({ state }) => {
			localStorage.setItem('rimworld-data', JSON.stringify(state));
		},
		clearStorage: ({ state }) => {
			state.data = [];
			//state.filter = filterDefault;
			state.settings = settingsDefault;
			localStorage.setItem('rimworld-data', JSON.stringify(state));
		}
	}
}

export default moduleRw;
