import { Pointer } from "./types";

// Clone object by converting to JSON and back
export const cloneJSON = <Type>(obj: Type): Type => {
	return JSON.parse(JSON.stringify(obj));
}

// Lazily apply OR to all methods in array
export const checkAllOr = (value: any, checks: Array<(value: any) => boolean>) => {
	for (const func of checks) {
		if (func(value)) {
			return true;
		}
	}
	return false;
}

// Lazily apply AND to all methods in array
export const checkAllAnd = (value: any, checks: Array<(value: any) => boolean>) => {
	for (const func of checks) {
		if (!func(value)) {
			return false;
		}
	}
	return true;
}

export const isObjectNotEmpty = (o: any) => {
	if (!o) return false;
	for (const p in o) {
		return true;
	}
	return false;
}

// Get pointer with string like "prop1/prop2/prop3"
export const getPropRef = (o: object, s: string): Pointer => {
	const a = s.split('/'); // Array
	if (a.length > 1) {
		let r: any = o; // Result
		for (let i = 0; i < a.length - 1; i++) {
			if (!isNaN(+a[i])) {
				r = r[+a[i]];
			} else {
				r = r[a[i]];
			}
		}
		return { obj: r, prop: a[a.length - 1] };
	} else {
		return { obj: o, prop: isNaN(+s) ? s : +s };
	}
};

// Assign value to deep property using string like "prop1/prop2/prop3"
export const assignDeepProp = (o: object, s: string, v: any): void => {
	const { obj, prop } = getPropRef(o, s);
	obj[prop] = v;
}

export const buildDictFromArray = <Type>(arr: any[], key: string) => {
	const dict: { [key: string]: Type } = {};
	for (const elem of arr) {
		dict[elem[key]] = elem;
	}
	return dict;
}
