import { Module } from 'vuex';
import { cloneJSON } from '@/helpers';
import { Attributes, Brother, BrotherClass } from '@/types/brotherTypes';
import { tiers, brotherDefault, brotherClassDefault, attributeMins } from '@/data/brothersData';

const module: Module<{ data: Brother[]; classes: BrotherClass[] }, any> = {
	namespaced: true,
	state: {
		data: [] as Brother[],
		classes: [] as BrotherClass[],
	},
	getters: {
		classesExtended(state) {
			return state.classes.map(item => {
				const ext = {
					...item,
					recruited: 0,
				}
				ext.recruited = state.data.filter(x => x.className === item.name).length;
				return ext;
			});
		},
		dataExtended(state) {
			return state.data.map(item => {
				const ext = {
					...item,
					activePerks: [] as number[],
					classObject: undefined as BrotherClass | undefined,
					lvlupsNeeded: {} as Attributes,
					totalLvlups: 0,
					overflow: 0,
				};
				const brotherClass = state.classes.find(x => x.name === item.className);
				if (brotherClass && item.className) {
					//Class
					ext.classObject = brotherClass;
					//Perks
					const blocks = brotherClass.link?.split('?')[1]?.split('&');
					if (blocks) {
						for (const block of blocks) {
							const [tier, index] = block.split('-');
							ext.activePerks.push(tiers[+tier - 1] + (+index - 1));
						}
					}
					//Attrs
					const attributeKeys = Object.keys(attributeMins);
					let total = 0;
					let overflow = 0;
					for (const key of attributeKeys) {
						if (!brotherClass.attr[key]) continue;
						const attr = item.attr[key] || 0;
						if (attr > brotherClass.attr[key]) continue;
						ext.lvlupsNeeded[key] = Math.ceil(
							(brotherClass.attr[key] - attr) / (attributeMins[key] + 1 + 0.5 * (item.talents[key] || 0))
						);
						total += ext.lvlupsNeeded[key] > 10 ? 10 : ext.lvlupsNeeded[key];
						overflow += ext.lvlupsNeeded[key] > 10 ? (ext.lvlupsNeeded[key] - 10) : 0;
					}
					ext.totalLvlups = total;
					ext.overflow = overflow;
				}
				return ext;
			})
		},
	},
	mutations: {
		addNewClass(state) {
			state.classes.push(cloneJSON(brotherClassDefault));
		},
		removeClass(state, { index }) {
			state.classes.splice(index, 1);
		},
		insertClass(state, { index, item }) {
			state.classes.splice(index, 0, item);
		},
		changeClassProp(state, { index, prop, value }) {
			if (prop === 'name') {
				for (const brother of state.data) {
					if (brother.className === state.classes[index][prop])
						brother.className = value;
				}
			}
			state.classes[index][prop] = value;
		},
		changeClassPropAttr(state, { index, prop, attr, value }) {
			if (value === 0) {
				state.classes[index][prop][attr] = undefined;
			} else {
				state.classes[index][prop][attr] = value;
			}
		},
		addNewItem(state) {
			state.data.push(cloneJSON(brotherDefault));
		},
		removeItem(state, { index }) {
			state.data.splice(index, 1);
		},
		insertItem(state, { index, item }) {
			state.data.splice(index, 0, item);
		},
		changeProp(state, { index, prop, value }) {
			state.data[index][prop] = value;
		},
		changePropAttr(state, { index, prop, attr, value }) {
			if (value === 0) {
				state.data[index][prop][attr] = undefined;
			} else {
				state.data[index][prop][attr] = value;
			}
		},
		cycleTalent(state, { index, attr }) {
			const val = state.data[index].talents[attr] || 0;
			state.data[index].talents[attr] = (val + 1) % 4;
			return;
		},
	},
	actions: {
		moveClass(context, { index, newIndex }) {
			const item = context.state.classes[index];
			context.commit('removeClass', { index });
			context.commit('insertClass', { index: newIndex, item });
		},
		moveItem(context, { index, newIndex }) {
			const item = context.state.data[index];
			context.commit('removeItem', { index });
			context.commit('insertItem', { index: newIndex, item });
		},
		loadFromStorage({ state }) {
			const obj = JSON.parse(localStorage.getItem('brothers-data') || '[]');
			state.data = obj.data || [];
			state.classes = obj.classes || [];
		},
		saveToStorage({ state }) {
			localStorage.setItem('brothers-data', JSON.stringify(state));
		},
		clearStorage({ state }) {
			localStorage.setItem('brothers-data', '{}');
			state.data = [];
			state.classes = [];
		},
		resetClasses({ state }) {
			state.classes = [];
			for (const brother of state.data) {
				brother.className = undefined;
			}
		},
		resetData({ state }) {
			state.data = [];
		},
	},
}

export default module;
